$selectors = @('Microsoft.BingSearch'; 'Clipchamp.Clipchamp'; 'Microsoft.549981C3F5F10'; 'Microsoft.Windows.DevHome'; 'MicrosoftCorporationII.MicrosoftFamily'; 'Microsoft.WindowsFeedbackHub'; 'Microsoft.Getstarted'; 'microsoft.windowscommunicationsapps'; 'Microsoft.WindowsMaps'; 'Microsoft.MixedReality.Portal'; 'Microsoft.BingNews'; 'Microsoft.OutlookForWindows'; 'Microsoft.PowerAutomateDesktop'; 'Microsoft.SkypeApp'; 'Microsoft.MicrosoftSolitaireCollection'; 'MicrosoftTeams'; 'MSTeams'; 'Microsoft.BingWeather'; 'Microsoft.ZuneVideo');
$getCommand = { Get-AppxProvisionedPackage -Online; };
$filterCommand = { $_.DisplayName -eq $selector; };
$removeCommand = { [CmdletBinding()] param([Parameter( Mandatory, ValueFromPipeline )] $InputObject) process { $InputObject | Remove-AppxProvisionedPackage -AllUsers -Online -ErrorAction 'Continue'; } };
$type = 'Package';
$logfile = 'C:\Windows\Setup\Scripts\RemovePackages.log';
& {
 $installed = & $getCommand;
 foreach( $selector in $selectors ) {
     $result = [ordered] @{ Selector = $selector; };
     $found = $installed | Where-Object -FilterScript $filterCommand;
     if( $found ) {
         $result.Output = $found | & $removeCommand;
         if( $? ) { $result.Message = "$type removed."; } else { $result.Message = "$type not removed."; $result.Error = $Error[0]; }
     } else { $result.Message = "$type not installed."; }
     $result | ConvertTo-Json -Depth 3 -Compress;
 }
} *>&1 | Out-String -Width 1KB -Stream >> $logfile;

