New-Item -Path $LogRoot -ItemType Directory -Force | Out-Null
$MainLog    = Join-Path $LogRoot "Install-All.log"

function Write-Log {
 param([string]$Message, [ValidateSet("INFO","WARN","ERROR","SUCCESS")] [string]$Level="INFO")
 $ts = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
 $line = "[$ts][$Level] $Message"
 $line | Out-File -FilePath $MainLog -Append -Encoding utf8

 if ($Level -eq "ERROR") { Write-Host $line -ForegroundColor Red }
 elseif ($Level -eq "WARN") { Write-Host $line -ForegroundColor Yellow }
 elseif ($Level -eq "SUCCESS") { Write-Host $line -ForegroundColor Green }
 else { Write-Host $line -ForegroundColor Cyan }
}

function Start-WaitWithTimeout {
 param([Parameter(Mandatory=$true)][string]$FilePath, [Parameter(Mandatory=$true)][string]$ArgumentList, [int]$TimeoutMinutes = 60)
 if ($FilePath -match "^[a-zA-Z]:\\") {
     $workDir = Split-Path $FilePath -Parent
     $p = Start-Process -FilePath $FilePath -ArgumentList $ArgumentList -WorkingDirectory $workDir -PassThru -WindowStyle Hidden
 } else {
     $p = Start-Process -FilePath $FilePath -ArgumentList $ArgumentList -PassThru -WindowStyle Hidden
 }
 $timeoutMs = $TimeoutMinutes * 60 * 1000
 if ($p.WaitForExit($timeoutMs)) { return @{ ExitCode = $p.ExitCode; TimedOut = $false } }
 else { try { $p.Kill() } catch {} return @{ ExitCode = 1460; TimedOut = $true } }
}

function Install-Package {
    param([string]$Name, [string]$Path, [string]$Type, [string]$ExeArgs = "", [int]$Timeout = 60)
    $FullPath = Join-Path $InstallDir $Path
    if (-not (Test-Path -LiteralPath $FullPath)) { Write-Log "[$Name] Ficheiro nao encontrado. A ignorar..." "WARN"; return }
    $fileName = Split-Path $FullPath -Leaf
    $pkgLog   = Join-Path $LogRoot ($fileName + ".log")

    Write-Log "[$Name] A iniciar instalacao..."
    if ($Type -eq "MSI") { $args = "/i `"$FullPath`" /qn /norestart /L*v `"$pkgLog`""; $exe = "msiexec.exe" }
    elseif ($Type -eq "MSP") { $args = "/p `"$FullPath`" /qn /norestart /L*v `"$pkgLog`""; $exe = "msiexec.exe" }
    elseif ($Type -eq "EXE") { 
        if ($ExeArgs -match "{LOGPATH}") { $ExeArgs = $ExeArgs -replace "{LOGPATH}", $pkgLog }
        $args = $ExeArgs; $exe = $FullPath
    }
    else { return }

    $r = Start-WaitWithTimeout -FilePath $exe -ArgumentList $args -TimeoutMinutes $Timeout

    # NOVO: Pausa de 10 segundos apos CADA instalacao para garantir que o msiexec liberta o sistema
    Write-Log "[$Name] Aguardando libertacao do sistema..."
    Start-Sleep -Seconds 10 

    if ($r.ExitCode -eq 0 -or $r.ExitCode -eq 3010) { Write-Log "[$Name] Finalizado com SUCESSO. ExitCode=$($r.ExitCode)" "SUCCESS" }
    else { Write-Log "[$Name] Finalizado com AVISO. ExitCode=$($r.ExitCode)" "WARN" }
}

