function Ensure-WUServices {
 Write-Host "=== INICIANDO O DOWNLOAD E INSTALACAO DE DRIVERS ===" -ForegroundColor Cyan
 $services = "wuauserv","bits","cryptsvc","usosvc"
 foreach ($s in $services) {
     $svc = Get-Service -Name $s -ErrorAction SilentlyContinue
     if (-not $svc) { continue }
     if ($svc.StartType -eq 'Disabled') { Set-Service $s -StartupType Manual }
     if ($svc.Status -ne 'Running') { Start-Service $s; Start-Sleep -Seconds 3 }
 }
}

function Enable-DriverUpdates {
 $regPaths = @("HKLM:\SOFTWARE\Policies\Microsoft\Windows\WindowsUpdate","HKLM:\SOFTWARE\Microsoft\PolicyManager\current\device\Update","HKLM:\SOFTWARE\Microsoft\PolicyManager\default\Update")
 foreach ($path in $regPaths) {
     if (-not (Test-Path $path)) { New-Item -Path $path -Force | Out-Null }
     New-ItemProperty -Path $path -Name "ExcludeWUDriversInQualityUpdate" -PropertyType DWord -Value 0 -Force | Out-Null
 }
}

function Enable-MicrosoftUpdate {
 try {
     $mgr = New-Object -ComObject Microsoft.Update.ServiceManager
     $mgr.AddService2($MicrosoftUpdateGuid, 7, "") | Out-Null
 } catch {}
}

function Run-DriverUpdates {
 param([int]$Pass)
 Write-Host "`n[Pesquisa] A procurar drivers na nuvem (Passo $Pass)..." -ForegroundColor Yellow
 $session  = New-Object -ComObject Microsoft.Update.Session
 $searcher = $session.CreateUpdateSearcher()
 $criteria = "IsInstalled=0 and Type='Driver' and IsHidden=0"
 $result   = $searcher.Search($criteria)

 if ($result.Updates.Count -eq 0) { 
     Write-Host "Nenhum driver pendente detetado." -ForegroundColor DarkGray
     return @{ Installed = 0; Reboot = $false } 
 }

 Write-Host "[Encontrado] O Windows detetou os seguintes drivers:" -ForegroundColor Green
 $updates = New-Object -ComObject Microsoft.Update.UpdateColl
 foreach ($u in $result.Updates) {
     Write-Host " -> $($u.Title)" -ForegroundColor White
     if (-not $u.EulaAccepted) { $u.AcceptEula() }
     $null = $updates.Add($u)
 }

 Write-Host "[A Descarregar] A extrair ficheiros..." -ForegroundColor Yellow
 $downloader = $session.CreateUpdateDownloader()
 $downloader.Updates = $updates
 $downloader.Download()

 $toInstall = New-Object -ComObject Microsoft.Update.UpdateColl
 foreach ($u in $updates) { if ($u.IsDownloaded) { $null = $toInstall.Add($u) } }

 if ($toInstall.Count -eq 0) { return @{ Installed = 0; Reboot = $false } }

 Write-Host "[A Instalar] A injetar drivers no sistema operativo..." -ForegroundColor Yellow
 $installer = $session.CreateUpdateInstaller()
 $installer.Updates = $toInstall
 $result = $installer.Install()

 return @{ Installed = $toInstall.Count; Reboot = [bool]$result.RebootRequired }
}

try {
 Ensure-WUServices
 Enable-DriverUpdates
