 $needsReboot = $false
 for ($i = 1; $i -le $MaxPasses; $i++) {
     $res = Run-DriverUpdates -Pass $i
     if ($res.Reboot) { $needsReboot = $true; break }
     if ($res.Installed -eq 0) { break }
     Start-Sleep -Seconds 5
 }

