     } catch {}
 };
);
& { foreach( $script in $scripts ) { & $script; } } *>&1 | Out-String -Width 1KB -Stream >> "$env:TEMP\UserOnce.log";

$scripts = @(
 { reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced" /v "HideFileExt" /t REG_DWORD /d 0 /f; };
 { reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced" /v ShowTaskViewButton /t REG_DWORD /d 0 /f; };
 { reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced" /v TaskbarEndTask /t REG_DWORD /d 1 /f; };
 { reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\Shell\Bags\1\Desktop" /v IconSize /t REG_DWORD /d 16 /f; };
 {
     reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\Explorer\HideDesktopIcons\NewStartPanel" /v "{20D04FE0-3AEA-1069-A2D8-08002B30309D}" /t REG_DWORD /d 0 /f;
     reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\Explorer\HideDesktopIcons\NewStartPanel" /v "{59031a47-3f72-44a7-89c5-5595fe6b30ee}" /t REG_DWORD /d 0 /f;
     reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\Explorer\HideDesktopIcons\NewStartPanel" /v "{5399E694-6CE5-4D6C-8FCE-1D8870FDCBA0}" /t REG_DWORD /d 0 /f;
     reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\Explorer\HideDesktopIcons\NewStartPanel" /v "{645FF040-5081-101B-9F08-00AA002F954E}" /t REG_DWORD /d 0 /f;
 };
 { & 'C:\Windows\Setup\Scripts\TurnOffSystemSounds.ps1'; };
 { reg.exe add "HKU\DefaultUser\Software\Policies\Microsoft\Windows\Explorer" /v DisableSearchBoxSuggestions /t REG_DWORD /d 1 /f; };
 { reg.exe add "HKU\DefaultUser\Software\Microsoft\Windows\CurrentVersion\RunOnce" /v "UnattendedSetup" /t REG_SZ /d "powershell.exe -WindowStyle `"`"Hidden`"`" -ExecutionPolicy `"`"Unrestricted`"`" -NoProfile -File `"`"C:\Windows\Setup\Scripts\UserOnce.ps1`"`"" /f; };
);
& { foreach( $script in $scripts ) { & $script; } } *>&1 | Out-String -Width 1KB -Stream >> "C:\Windows\Setup\Scripts\DefaultUser.log";

$scripts = @(
 { Set-ItemProperty -LiteralPath 'Registry::HKLM\SOFTWARE\Microsoft\Windows NT\CurrentVersion\Winlogon' -Name 'AutoLogonCount' -Type 'DWord' -Force -Value 0; };
 {
     $name = 'WlanSvc';
     $start = [datetime]::Now;
     $timeout = $start.AddMinutes( 1 );
     while( $true ) {
         if( $service = Get-Service -Name $name -ErrorAction 'SilentlyContinue' ) {
             if( $service.Status -eq 'Running' ) { break; }
         }
         if( [datetime]::Now -gt $timeout ) { break; }
         Start-Sleep -Seconds 5;
     }
 };
 {
    netsh.exe wlan add profile filename="C:\Windows\Setup\Scripts\Wifi.xml" user=all;
    netsh.exe wlan connect name="PB-GUEST" ssid="PB-GUEST";
    Write-Output 'A aguardar negociacao de IP e acesso a Internet (Bloqueio estrito)...';

    while (!(Test-Connection -ComputerName 8.8.8.8 -Count 1 -Quiet -ErrorAction SilentlyContinue)) { 
        Write-Output 'Rede indisponivel. A re-testar em 5 segundos...';
        Start-Sleep -Seconds 5; 
    }

    Write-Output 'Acesso a Internet confirmado. A iniciar instalacoes...';
 };
 {
     Write-Output 'A procurar a pasta Installers na pen USB...';
     $found = $false;
     foreach( $drive in (Get-PSDrive -PSProvider FileSystem).Name ) {
         $paths = @( ($drive + ':\Installers'), ($drive + ':\$OEM$\$1\Installers'), ($drive + ':\sources\$OEM$\$1\Installers') )
         foreach( $source in $paths ) {
             if( Test-Path -LiteralPath $source ) {
                 New-Item -Path 'C:\Installers' -ItemType Directory -Force | Out-Null;
                 Copy-Item -Path "$source\*" -Destination 'C:\Installers' -Recurse -Force;
                 $found = $true;
                 break;
             }
         }
         if ($found) { break; }
     }
 };
 {
     # SOFTWARE PRIMEIRO: Instala Office, Adobe, etc.
     Start-Process powershell.exe -ArgumentList "-NoProfile -ExecutionPolicy Bypass -File `"C:\Windows\Setup\Scripts\unattend-02.ps1`"" -WindowStyle Normal -Wait;
 };
 {
     # DRIVERS DEPOIS: Inicia a pesquisa do Windows Update para hardware
     Start-Process powershell.exe -ArgumentList "-NoProfile -ExecutionPolicy Bypass -File `"C:\Windows\Setup\Scripts\unattend-03.ps1`"" -WindowStyle Normal -Wait;
 };
 { Remove-Item -LiteralPath @( 'C:\Windows\Panther\unattend.xml'; 'C:\Windows\Setup\Scripts\Wifi.xml' ) -Force -ErrorAction 'SilentlyContinue'; };
);
& { foreach( $script in $scripts ) { & $script; } } *>&1 | Out-String -Width 1KB -Stream >> "C:\Windows\Setup\Scripts\FirstLogon.log";
